const texto = (msg.payload || '').toLowerCase().trim();

if (texto.includes('chuva hoje')) {
    msg.comando = 'chuva_hoje';
    msg.url = 'https://api.ipma.pt/open-data/forecast/meteorology/cities/daily/1040200.json';
} else if (texto.includes('chuva amanhã') || texto.includes('chuva amanha')) {
    msg.comando = 'chuva_amanha';
    msg.url = 'https://api.ipma.pt/open-data/forecast/meteorology/cities/daily/1040200.json';
} else if (texto.includes('temperatura')) {
    msg.comando = 'temperatura';
    msg.url = 'https://api.ipma.pt/open-data/observation/meteorology/stations/observations.json';
} else if (texto.includes('humidade')) {
    msg.comando = 'humidade';
    msg.url = 'https://api.ipma.pt/open-data/observation/meteorology/stations/observations.json';
} else {
    msg.comando = 'desconhecido';
    msg.payload = 'Comando não reconhecido. Tente: Previsão de Chuva Hoje, Previsão de Chuva Amanhã, Temperatura Atual ou Humidade Atual.';
    msg.url = null;
}

return msg;

const comando = msg.comando;
const dados = msg.payload;
let resposta = 'Não entendi o comando. Tente novamente.';

if (comando === 'chuva_hoje') {
    const hoje = dados.data[0];
    resposta = `Probabilidade de Chuva hoje é de ${hoje.precipitaProb} porcento`;

} else if (comando === 'chuva_amanha') {
    const amanha = dados.data[1];
    resposta = `Probabilidade de chuva para amanhã é de ${amanha.precipitaProb} porcento`;

} else if (comando === 'temperatura') {
    const idEstacao = '1200575';
    const horas = Object.keys(dados).sort().reverse();
    let temp = null;
    for (const h of horas) {
        const e = dados[h][idEstacao];
        if (e && e.temperatura !== -99.0) {
            temp = e.temperatura;
            break;
        }
    }
    resposta = temp !== null
        ? `A temperatura atual é de ${temp} graus Celsius`
        : 'Não foi possível obter a temperatura atual';

} else if (comando === 'humidade') {
    const idEstacao = '1200575';
    const horas = Object.keys(dados).sort().reverse();
    let hum = null;
    for (const h of horas) {
        const e = dados[h][idEstacao];
        if (e && e.humidade !== -99.0) {
            hum = e.humidade;
            break;
        }
    }
    resposta = hum !== null
        ? `A humidade relativa do ar atual é de ${hum} porcento`
        : 'Não foi possível obter a humidade atual';
}

msg.payload = resposta;
return msg;

const texto = encodeURIComponent(msg.payload);
msg.url = `https://translate.google.com/translate_tts?ie=UTF-8&q=${texto}&tl=pt&client=tw-ob`;
msg.headers = { 'User-Agent': 'Mozilla/5.0' };
return msg;
